const statsRaw = $input.first().json;
const stats = statsRaw.data || statsRaw;

if (!Array.isArray(stats)) {
  return [{ json: { error: 'No device stats' } }];
}

// Group by ad_group_id, then by device_type_id
const groupMap = {};
stats.forEach(s => {
  const agId = s.ad_group_id;
  const dtId = s.device_type_id;
  if (!agId || !dtId) return;

  if (!groupMap[agId]) groupMap[agId] = {};
  if (!groupMap[agId][dtId]) {
    groupMap[agId][dtId] = { spend: 0, revenue: 0, clicks: 0 };
  }
  groupMap[agId][dtId].spend += parseFloat(s.money) || 0;
  groupMap[agId][dtId].revenue += parseFloat(s.postbacks_confirmed_money) || 0;
  groupMap[agId][dtId].clicks += parseInt(s.clicks_count) || 0;
});

// Calculate coefficients per ad_group
const results = [];
for (const [agId, devices] of Object.entries(groupMap)) {
  const osCoeff = {};

  for (const [dtId, d] of Object.entries(devices)) {
    const roi = d.spend > 0 ? ((d.revenue - d.spend) / d.spend * 100) : 0;

    let coefficient = 1.0;
    if (roi > 30 && d.clicks > 10) {
      coefficient = 1.3; // More traffic from profitable segments
    } else if (roi >= 0 && roi <= 30) {
      coefficient = 1.0; // Normal
    } else if (roi >= -30 && roi < 0 && d.clicks > 10) {
      coefficient = 0.7; // Less traffic
    } else if (roi < -30 && d.clicks > 10) {
      coefficient = 0.3; // Almost disable
    }

    osCoeff[dtId] = Math.round(coefficient * 10) / 10;
  }

  results.push({
    json: {
      ad_group_id: parseInt(agId),
      coefficients: {
        os: osCoeff
      },
      details: Object.entries(devices).map(([dtId, d]) => ({
        device_type_id: dtId,
        spend: Math.round(d.spend * 100) / 100,
        revenue: Math.round(d.revenue * 100) / 100,
        roi: d.spend > 0 ? Math.round((d.revenue - d.spend) / d.spend * 10000) / 100 : 0,
        coefficient: osCoeff[dtId]
      }))
    }
  });
}

if (results.length === 0) {
  return [{ json: { action: 'SKIP', reason: 'No data for coefficient tuning' } }];
}

return results;

